// Vanilla JS, no build step, no framework - deliberately, to keep this a
// thin presentation layer over the existing REST API (POST /analyze,
// POST /compare). Every number/fact rendered here comes straight from the
// API response; this file only formats it. UI-chrome strings go through
// t() (see i18n.js) - the analysis content itself (recommendation text,
// "Missing required skill: X", etc.) is generated by 01-domain in English
// and is not translated by this file.

function switchTab(tabName) {
  document.querySelectorAll('.tab-button').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.tab === tabName);
  });
  document.querySelectorAll('.tab-panel').forEach(panel => {
    panel.classList.toggle('active', panel.id === `${tabName}-tab`);
  });
}

document.querySelectorAll('.tab-button').forEach(btn => {
  btn.addEventListener('click', () => switchTab(btn.dataset.tab));
});

function formatFromFilename(name) {
  const lower = name.toLowerCase();
  if (lower.endsWith('.pdf')) return 'pdf';
  if (lower.endsWith('.docx')) return 'docx';
  return null;
}

function fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      // readAsDataURL yields "data:<mime>;base64,<data>" - the API only
      // wants the raw base64 payload, same shape infrastructure/extract-text.ts
      // decodes on the server.
      const commaIndex = reader.result.indexOf(',');
      resolve(reader.result.slice(commaIndex + 1));
    };
    reader.onerror = () => reject(reader.error);
    reader.readAsDataURL(file);
  });
}

// A resume/job "document" is either pasted text or an uploaded file - if a
// file is present it wins over whatever is in the textarea, since selecting
// a file is a clearer signal of intent than stale placeholder text.
async function resolveDocument(textEl, fileEl) {
  const file = fileEl.files[0];
  if (file) {
    const format = formatFromFilename(file.name);
    if (format) {
      return { base64: await fileToBase64(file), format };
    }
    return { text: await file.text() };
  }
  return { text: textEl.value };
}

function isEmptyDocument(doc) {
  return 'text' in doc && !doc.text.trim();
}

function formatConfidence(confidence) {
  return typeof confidence === 'number' ? `${confidence}%` : t('results.confidenceNA');
}

function categoryLabel(category) {
  return translations[currentLang].categories[category] || (category.charAt(0).toUpperCase() + category.slice(1));
}

function renderCategory(category) {
  const matchedItems = category.matched.map(item => `<li class="matched">+ ${escapeHtml(item)}</li>`).join('');
  const missingItems = category.missing.map(item => `<li class="missing">- ${escapeHtml(item)} ${t('results.missingSuffix')}</li>`).join('');
  return `
    <div class="category">
      <div class="category-label"><span>${categoryLabel(category.category)}</span><span class="score">${category.score}</span></div>
      <div class="bar-track"><div class="bar-fill" style="width:${Math.max(0, Math.min(100, category.score))}%"></div></div>
      <ul class="fact-list">${matchedItems}${missingItems}</ul>
    </div>`;
}

function renderRecommendations(title, recommendations) {
  if (!recommendations || !recommendations.length) return '';
  const items = recommendations.map(rec => `
    <div class="recommendation">
      <span class="severity-badge severity-${rec.severity || 'low'}">${rec.severity || 'info'}</span>
      <span>${escapeHtml(rec.text)}</span>
    </div>`).join('');
  return `<div class="recommendations"><h3>${title}</h3>${items}</div>`;
}

function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

function renderAnalysisResult(result) {
  const { analysis, explanation, recommendations, aiRecommendations, recommendationError } = result;
  const categories = explanation.map(renderCategory).join('');
  const warnings = analysis.warnings && analysis.warnings.length
    ? `<p class="status error">${analysis.warnings.map(escapeHtml).join(' - ')}</p>`
    : '';
  const errorNote = recommendationError
    ? `<p class="status error">${t('results.recommendationErrorPrefix')}${escapeHtml(recommendationError)}</p>`
    : '';

  return `
    <div class="result-card">
      <div class="result-header">
        <h2>${t('results.overall')}: ${analysis.overall}%</h2>
        <span class="confidence">${t('results.confidence')}: ${formatConfidence(analysis.confidence)}</span>
      </div>
      ${warnings}
      ${categories}
      ${renderRecommendations(t('results.recommendations'), recommendations)}
      ${renderRecommendations(t('results.aiRecommendations'), aiRecommendations)}
      ${errorNote}
    </div>`;
}

// The no-job counterpart to renderAnalysisResult: there is no overall
// score/breakdown to show (see analyze-resume.ts's own reasoning on the
// backend) - this shows what was actually extracted from the document
// instead of a comparison that has nothing to compare against.
function renderResumeInsight(insight) {
  const list = (items, formatItem) => items.length
    ? items.map(item => `<li>${formatItem(item)}</li>`).join('')
    : `<li class="muted">${t('results.noneDetected')}</li>`;

  const skillsList = list(insight.skills, skill => {
    const label = escapeHtml(skill.canonical || skill.raw);
    const tag = skill.category ? `<span class="tag">${escapeHtml(skill.category)}</span>` : '';
    return `${label}${tag}`;
  });

  const experienceList = list(insight.experience, entry => {
    const title = [entry.title, entry.company].filter(Boolean).join(` ${t('results.at')} `) || t('results.untitledEntry');
    const dates = entry.startDate ? ` (${escapeHtml(entry.startDate)} - ${escapeHtml(entry.endDate || '?')})` : '';
    return `${escapeHtml(title)}${dates}`;
  });

  const educationList = list(insight.education, entry => {
    const label = [entry.degree, entry.institution].filter(Boolean).join(' - ') || t('results.untitledEntry');
    return escapeHtml(label);
  });

  const warnings = insight.warnings && insight.warnings.length
    ? `<p class="status error">${insight.warnings.map(escapeHtml).join(' - ')}</p>`
    : '';

  return `
    <div class="result-card">
      <div class="result-header">
        <h2>${t('results.insightTitle')}</h2>
        <span class="confidence">${t('results.totalExperience')}: ${insight.totalExperienceYears} ${t('results.years')}</span>
      </div>
      ${warnings}
      <div class="insight-section">
        <h3>${t('categories.skills')}</h3>
        <ul class="fact-list">${skillsList}</ul>
      </div>
      <div class="insight-section">
        <h3>${t('categories.experience')}</h3>
        <ul class="fact-list">${experienceList}</ul>
      </div>
      <div class="insight-section">
        <h3>${t('categories.education')}</h3>
        <ul class="fact-list">${educationList}</ul>
      </div>
    </div>`;
}

// Dispatches on which endpoint produced the stored result, so a language
// switch re-render (see the languagechange-app listener below) renders
// whichever shape is actually on screen.
function renderAnalyzeOutput(result) {
  return result.mode === 'insight' ? renderResumeInsight(result.body.insight) : renderAnalysisResult(result.body);
}

// --- Analyze tab ---

const analyzeForm = document.getElementById('analyze-form');
const analyzeStatus = document.getElementById('analyze-status');
const analyzeResults = document.getElementById('analyze-results');
const analyzeNoJobToggle = document.getElementById('analyze-no-job');
const analyzeJobText = document.getElementById('analyze-job-text');
const analyzeJobFile = document.getElementById('analyze-job-file');
// Kept so a language switch after a result is already on screen can
// re-render it in the new language without re-calling the API. Shape:
// { mode: 'match' | 'insight', body }.
let lastAnalyzeResult = null;

analyzeNoJobToggle.addEventListener('change', () => {
  const noJob = analyzeNoJobToggle.checked;
  analyzeJobText.disabled = noJob;
  analyzeJobFile.disabled = noJob;
});

analyzeForm.addEventListener('submit', async event => {
  event.preventDefault();
  analyzeResults.innerHTML = '';
  lastAnalyzeResult = null;
  analyzeStatus.className = 'status';

  const resume = await resolveDocument(
    document.getElementById('analyze-resume-text'),
    document.getElementById('analyze-resume-file')
  );
  const noJob = analyzeNoJobToggle.checked;

  if (isEmptyDocument(resume)) {
    analyzeStatus.textContent = t(noJob ? 'analyze.statusMissingResumeOnly' : 'analyze.statusMissing');
    analyzeStatus.className = 'status error';
    return;
  }

  let job;
  if (!noJob) {
    job = await resolveDocument(
      document.getElementById('analyze-job-text'),
      document.getElementById('analyze-job-file')
    );
    if (isEmptyDocument(job)) {
      analyzeStatus.textContent = t('analyze.statusMissing');
      analyzeStatus.className = 'status error';
      return;
    }
  }

  analyzeStatus.textContent = t('analyze.statusAnalyzing');
  const submitButton = analyzeForm.querySelector('button[type="submit"]');
  submitButton.disabled = true;

  try {
    const response = await fetch(noJob ? '/analyze-resume' : '/analyze', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(noJob ? { resume } : { resume, job })
    });
    const body = await response.json();
    if (!response.ok) throw new Error(body.error || t('errors.requestFailed', { status: response.status }));
    analyzeStatus.textContent = '';
    lastAnalyzeResult = { mode: noJob ? 'insight' : 'match', body };
    analyzeResults.innerHTML = renderAnalyzeOutput(lastAnalyzeResult);
  } catch (error) {
    analyzeStatus.textContent = error.message;
    analyzeStatus.className = 'status error';
  } finally {
    submitButton.disabled = false;
  }
});

// --- Compare tab ---

const candidateList = document.getElementById('candidate-list');
const candidateTemplate = document.getElementById('candidate-template');
const addCandidateButton = document.getElementById('add-candidate');
const compareForm = document.getElementById('compare-form');
const compareStatus = document.getElementById('compare-status');
const compareResults = document.getElementById('compare-results');
let lastCompareResult = null;

function addCandidateRow(prefill) {
  const node = candidateTemplate.content.cloneNode(true);
  translateElement(node);
  if (prefill) {
    node.querySelector('.candidate-id').value = prefill.id;
    node.querySelector('.candidate-text').value = prefill.text;
  }
  node.querySelector('.remove-candidate').addEventListener('click', event => {
    event.target.closest('.candidate').remove();
  });
  candidateList.appendChild(node);
}

addCandidateButton.addEventListener('click', () => addCandidateRow());
// Start with 2 candidate rows - compareResumesToJob requires at least 2.
addCandidateRow();
addCandidateRow();

function renderCompareResults(body) {
  const rows = body.results.map(result => `
    <div class="compare-row">
      <span class="rank">#${result.rank}</span>
      <span class="name">${escapeHtml(result.id)}</span>
      <span class="scores">${t('results.overall')} ${result.analysis.overall}% &middot; ${t('results.confidence').toLowerCase()} ${formatConfidence(result.analysis.confidence)}</span>
    </div>`).join('');
  const label = t('compare.comparedLabel', { count: body.compared, date: new Date(body.generatedAt).toLocaleString() });
  return `<p class="status">${label}</p>${rows}`;
}

compareForm.addEventListener('submit', async event => {
  event.preventDefault();
  compareResults.innerHTML = '';
  lastCompareResult = null;
  compareStatus.className = 'status';

  const job = await resolveDocument(
    document.getElementById('compare-job-text'),
    document.getElementById('compare-job-file')
  );
  if (isEmptyDocument(job)) {
    compareStatus.textContent = t('compare.statusMissingJob');
    compareStatus.className = 'status error';
    return;
  }

  const candidateEls = Array.from(candidateList.querySelectorAll('.candidate'));
  if (candidateEls.length < 2) {
    compareStatus.textContent = t('compare.statusMinCandidates');
    compareStatus.className = 'status error';
    return;
  }

  const resumes = [];
  for (const [index, el] of candidateEls.entries()) {
    const idInput = el.querySelector('.candidate-id');
    const id = idInput.value.trim() || t('compare.candidateDefaultName', { n: index + 1 });
    const document_ = await resolveDocument(el.querySelector('.candidate-text'), el.querySelector('.candidate-file'));
    if (isEmptyDocument(document_)) {
      compareStatus.textContent = t('compare.statusMissingCandidate', { name: id });
      compareStatus.className = 'status error';
      return;
    }
    resumes.push({ id, document: document_ });
  }

  const ids = resumes.map(r => r.id);
  if (new Set(ids).size !== ids.length) {
    compareStatus.textContent = t('compare.statusDuplicateIds');
    compareStatus.className = 'status error';
    return;
  }

  compareStatus.textContent = t('compare.statusComparing');
  const submitButton = compareForm.querySelector('button[type="submit"]');
  submitButton.disabled = true;

  try {
    const response = await fetch('/compare', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ job, resumes })
    });
    const body = await response.json();
    if (!response.ok) throw new Error(body.error || t('errors.requestFailed', { status: response.status }));
    compareStatus.textContent = '';
    lastCompareResult = body;
    compareResults.innerHTML = renderCompareResults(body);
  } catch (error) {
    compareStatus.textContent = error.message;
    compareStatus.className = 'status error';
  } finally {
    submitButton.disabled = false;
  }
});

// --- Language switch re-render ---
// i18n.js dispatches this after applying static translations - re-render
// only what's already on screen, in the new language, without re-fetching.
window.addEventListener('languagechange-app', () => {
  if (lastAnalyzeResult) analyzeResults.innerHTML = renderAnalyzeOutput(lastAnalyzeResult);
  if (lastCompareResult) compareResults.innerHTML = renderCompareResults(lastCompareResult);
});

// --- Try with example data ---
// The single most effective onboarding for a tool like this: one click
// shows real output instead of asking a first-time visitor to write or dig
// up their own resume text before they even know what the page does.

document.getElementById('analyze-example').addEventListener('click', () => {
  // The example demonstrates the job-match path specifically, so it resets
  // the no-job toggle rather than leaving it in whatever state the visitor
  // last left it in.
  analyzeNoJobToggle.checked = false;
  analyzeJobText.disabled = false;
  analyzeJobFile.disabled = false;
  document.getElementById('analyze-resume-text').value = SAMPLE_DATA.analyze.resume;
  document.getElementById('analyze-resume-file').value = '';
  document.getElementById('analyze-job-text').value = SAMPLE_DATA.analyze.job;
  document.getElementById('analyze-job-file').value = '';
  analyzeStatus.textContent = '';
  analyzeStatus.className = 'status';
});

document.getElementById('compare-example').addEventListener('click', () => {
  document.getElementById('compare-job-text').value = SAMPLE_DATA.compare.job;
  document.getElementById('compare-job-file').value = '';
  candidateList.innerHTML = '';
  SAMPLE_DATA.compare.candidates.forEach(candidate => addCandidateRow(candidate));
  compareStatus.textContent = '';
  compareStatus.className = 'status';
});
